<template>
  <div class="app-container">
    <header class="header-section">
      <div class="saluti">
        <span class="icona-saluto">👋</span>
        <h1 class="testo-saluto">Ciao, {{ username }}!</h1>
      </div>
      <p class="sottotesto">Speriamo tu abbia una giornata fantastica!</p>

      <div class="logout-btn-container">
        <button @click="logout" class="logout-btn">
          <font-awesome-icon icon="fa-sign-out-alt" /> Logout
        </button>
      </div>
    </header>

    <section class="cards-container">
      <!-- Card Note -->
      <div class="card note-card">
        <div class="card-header">
          <font-awesome-icon icon="fa-sticky-note" />
          <h2>Ultima nota</h2>
        </div>
        <div class="card-content">
          <template v-if="lastNote">
            <div class="note-content">
              <h3 class="titolo-nota">{{ lastNote.titolo }}</h3>
              <div class="categoria-nota" v-if="lastNote.categoria">
                <span class="label-categoria">Categoria:</span>
                <span class="testo-categoria">{{ lastNote.categoria }}</span>
              </div>
              <p
                class="descrizione-nota"
                v-html="renderMarkdown(lastNote.descr)"
              ></p>
              <div class="info-nota">
                <span class="data-nota">
                  <font-awesome-icon icon="fa-calendar-check" />
                  Creata il {{ formatDate(lastNote.data_cr) }}
                </span>
                <span class="data-nota">
                  <font-awesome-icon icon="fa-edit" />
                  Modificata il {{ formatDate(lastNote.data_md) }}
                </span>
              </div>
            </div>
          </template>
          <template v-else>
            <p class="testo-vuoto">Nessuna nota trovata</p>
          </template>
        </div>
      </div>

      <!-- Card Evento -->
      <div class="card event-card">
        <div class="card-header">
          <font-awesome-icon icon="fa-calendar-alt" />
          <h2>Prossimo evento</h2>
        </div>
        <div class="card-content">
          <template v-if="nextEvento">
            <div class="note-content">
              <h3 class="titolo-nota">{{ nextEvento.titolo }}</h3>
              <div>
                <p
                  class="descrizione-nota"
                  v-html="renderMarkdown(nextEvento.descr)"
                ></p>
                <span v-if="isToday(nextEvento.data_ev)">oggi</span>
                <span v-else>{{ formatDate(nextEvento.data_ev) }}</span>
                <span> alle {{ formatHour(nextEvento.data_ev) }}</span>
              </div>
              <div v-if="nextEvento.location">
                <strong>Luogo:</strong> {{ nextEvento.location }}
              </div>
              <div v-else-if="nextEvento.luogo">
                <strong>Luogo:</strong> {{ nextEvento.luogo }}
              </div>
              <div v-if="nextEvento.latitude && nextEvento.longitude">
                <font-awesome-icon
                  icon="fa-map-marker-alt"
                  style="margin-right: 0.3em"
                />
                <small>
                  Coordinate: {{ nextEvento.latitude.toFixed(5) }},
                  {{ nextEvento.longitude.toFixed(5) }}
                </small>
              </div>
            </div>
          </template>
          <template v-else>
            <p class="testo-vuoto">Nessun evento programmato</p>
          </template>
        </div>
      </div>

      <!-- Card Pomodoro -->
      <div class="card pomodoro-card">
        <div class="card-header">
          <font-awesome-icon icon="fa-clock" />
          <h2>Ultimo pomodoro</h2>
        </div>
        <div class="card-content">
          <p class="testo-vuoto" v-if="!lastPomodoro">
            Nessun pomodoro recente
          </p>
          <div class="note-content" v-else>
            <p>Studio: {{ lastPomodoro.studio_rimasto }} / {{ lastPomodoro.studio }}</p>
            <p>Pausa: {{ lastPomodoro.pausa_rimasta }} / {{ lastPomodoro.pausa }}</p>
            <p>Cicli: {{ lastPomodoro.cicli_rimasti }} / {{ lastPomodoro.ciclo }}</p>
          </div>
        </div>
      </div>
    </section>
  </div>
</template>

<script>
import { isAuthenticated } from "@/utils/auth";
import { library } from "@fortawesome/fontawesome-svg-core";
import {
  faCalendarAlt,
  faCalendarCheck,
  faClock,
  faEdit,
  faLightbulb,
  faSignOutAlt,
  faStickyNote,
} from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/vue-fontawesome";
import { marked } from "marked";

library.add(
  faSignOutAlt,
  faLightbulb,
  faStickyNote,
  faCalendarAlt,
  faClock,
  faCalendarCheck,
  faEdit
);

let backendHost = `http://${window.location.hostname}:3000`;

export default {
  name: "HomePage",
  components: {
    FontAwesomeIcon,
  },

  computed: {
    isAuthenticated() {
      return isAuthenticated();
    },
  },

  data() {
    return {
      username: "",
      email: "",
      lastNote: null,
      nextEvento: null,
      lastPomodoro: null,
      error: null,
      virtualDate: "",
    };
  },

  created() {
    this.username = localStorage.getItem("username");
    this.email = localStorage.getItem("email") || "";
  },

  methods: {
    handleTimeChange(newTime) {
      this.$store.commit("updateTime", newTime);
    },

    logout() {
      localStorage.removeItem("username");
      localStorage.removeItem("email");
      localStorage.removeItem("token");
      this.$router.push("/login");
    },

    formatDate(dateString) {
      return new Date(dateString).toLocaleDateString();
    },

    // Recupera l'ultima nota
    async fetchLastNote() {
      try {
        const user = this.username;
        // Prende l'ultima nota dell'utente tramite una chiamata al backend GET
        const risposta = await fetch(
          `${backendHost}/api/note/get?autore=${encodeURIComponent(user)}`,
          {
            method: "GET",
            headers: { "Content-Type": "application/json" },
          }
        );

        // Controlla se la risposta è andata a buon fine
        if (!risposta.ok) {
          this.lastNote = null;
          return;
        }

        // Converte la risposta in JSON e aggiorna lastNote
        const data = await risposta.json();
        this.lastNote = data.UltimaNota;
      } catch (error) {
        console.error(error);
        this.error = "Errore nel caricamento della nota";
        this.lastNote = null;
      }
    },

    renderMarkdown(t) {
      return marked.parse(t);
    },

    async fetchEvento() {
      try {
        const user = this.username;
        // Prende tutti gli eventi dell'utente tramite una chiamata al backend GET
        const risposta = await fetch(
          `${backendHost}/api/calendar/getAll?author=${encodeURIComponent(
            user
          )}`,
          {
            method: "GET",
            headers: { "Content-Type": "application/json" },
          }
        );

        if (!risposta.ok) {
          this.nextEvento = null;
          return;
        }

        const data = await risposta.json();
        const eventi = data.eventi || [];

        // Ottieni la data virtuale dalla time machine (se presente)
        let virtualDate = null;
        try {
          // Chiamata diretta all'API della time machine
          const res = await fetch(`${backendHost}/api/time-machine`);
          if (res.ok) {
            const d = await res.json();
            if (d && d.time) {
              virtualDate = new Date(d.time);
              virtualDate.setHours(0, 0, 0, 0);
            }
          }
        } catch (e) {
          virtualDate = null;
        }

        // Data di oggi (solo data, senza orario)
        let oggi = new Date();
        oggi.setHours(0, 0, 0, 0);
        if (virtualDate) {
          oggi = virtualDate;
        }

        // Filtra eventi con data_ev >= oggi
        const eventiFuturi = eventi.filter((ev) => {
          const dataEv = new Date(ev.data_ev);
          dataEv.setHours(0, 0, 0, 0);
          return dataEv >= oggi;
        });

        // Trova l'evento con la data più vicina a oggi
        let prossimo = null;
        if (eventiFuturi.length > 0) {
          prossimo = eventiFuturi.reduce((a, b) => {
            const dataA = new Date(a.data_ev);
            const dataB = new Date(b.data_ev);
            return dataA < dataB ? a : b;
          });
        }

        // Salva anche la virtualDate per il template
        this.virtualDate = oggi;
        this.nextEvento = prossimo;

        // Se c'è un evento oggi che inizia entro 30 minuti o adesso, invia la mail solo 2 volte (1 per soglia, 1 per inizio)
        if (prossimo && this.email) {
          const eventoDate = new Date(prossimo.data_ev);
          const now = new Date();
          const diffMs = eventoDate - now;
          const eventKey = `notifica_evento_${prossimo.titolo}_${prossimo.data_ev}`;
          let notifyState = localStorage.getItem(eventKey);

          // Notifica "manca meno di 30 minuti"
          if (
            this.isToday(prossimo.data_ev) &&
            diffMs > 0 &&
            diffMs <= 30 * 60 * 1000 &&
            notifyState !== "30min"
          ) {
            alert(
              `L'evento "${prossimo.titolo}" inizia tra meno di 30 minuti!`
            );
            try {
              await fetch(`${backendHost}/api/calendar/notify-imminent`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  email: this.email,
                  titolo: prossimo.titolo,
                  data_ev: prossimo.data_ev,
                  descr: prossimo.descr || "",
                  isNow: false,
                }),
              });
              localStorage.setItem(eventKey, "30min");
            } catch (e) {
              console.error("Errore nell'invio della mail:", e);
            }
          }

          // Notifica "evento adesso"
          if (
            this.isToday(prossimo.data_ev) &&
            Math.abs(diffMs) < 60 * 1000 && // entro 1 minuto dall'orario
            notifyState !== "adesso"
          ) {
            alert(`L'evento "${prossimo.titolo}" sta iniziando ora!`);
            try {
              await fetch(`${backendHost}/api/calendar/notify-imminent`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                  email: this.email,
                  titolo: prossimo.titolo,
                  data_ev: prossimo.data_ev,
                  descr: prossimo.descr || "",
                  isNow: true,
                }),
              });
              localStorage.setItem(eventKey, "adesso");
            } catch (e) {
              console.error("Errore nell'invio della mail:", e);
            }
          }
        }
      } catch (error) {
        console.error(error);
        this.error = "Errore nel caricamento dell'evento";
        this.nextEvento = null;
      }
    },
    isToday(dateString) {
      if (!dateString || !this.virtualDate) return false;
      const d1 = new Date(dateString);
      d1.setHours(0, 0, 0, 0);
      const d2 = new Date(this.virtualDate);
      d2.setHours(0, 0, 0, 0);
      return d1.getTime() === d2.getTime();
    },

    formatHour(dateString) {
      const date = new Date(dateString);
      return date.toLocaleTimeString([], {
        hour: "2-digit",
        minute: "2-digit",
      });
    },

    async fetchPomodoro() {
      try {
        const user = this.username;
        // Prende l'ultima nota dell'utente tramite una chiamata al backend GET
        const risposta = await fetch(
          `${backendHost}/api/pomodoro/getLast?autore=${encodeURIComponent(
            user
          )}`,
          {
            method: "GET",
            headers: { "Content-Type": "application/json" },
          }
        );

        // Controlla se la risposta è andata a buon fine
        if (!risposta.ok) {
          this.lastPomodoro = null;
          return;
        }

        // Converte la risposta in JSON e aggiorna lastNote
        const data = await risposta.json();
        this.lastPomodoro = data.ultimoTimer;
      } catch (error) {
        console.error(error);
        this.error = "Errore nel caricamento del pomodoro";
        this.lastPomodoro = null;
      }
    },
  },

  mounted() {
    this.fetchLastNote();
    this.fetchEvento();
    this.fetchPomodoro();
  },
};
</script>

<style>
/* Variabili CSS globali per i colori e lo stile dell'app */
:root {
  --primary-color: #6366f1; /* Colore nota (viola) */
  --secondary-color: #48a8ec; /* Colore evento (azzurro) */
  --accent-color: #ba2815; /* Colore di pomodoro (rosso) */
  --text-color: #1f2937; /* Colore del testo principale */
  --light-color: #f9fafb; /* Colore di sfondo chiaro */
  --gray-color: #9ca3af; /* Colore grigio per i titoli */
  --card-bg: #ffffff; /* Sfondo delle card */
  --card-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1),
    0 4px 6px -2px rgba(0, 0, 0, 0.05); /* Ombra delle card */
  --gradient-bg: linear-gradient(
    120deg,
    #3134e7 0%,
    #48b2ec 100%
  ); /* Sfondo gradiente header principale */
  --border-radius: 1em; /* Raggio dei bordi per elementi arrotondati */
}

/* Contenitore Principale */
.app-container {
  min-height: 100%;
  min-width: 70%;
  max-width: 90%;
  background-color: transparent;
  padding: 1.5em;
  font-family: "Poppins", sans-serif;
  color: var(--text-color);
}

/* Sezione header */
.header-section {
  background: var(--gradient-bg);
  border-radius: var(--border-radius);
  padding: 2em;
  color: white;
  text-align: center;
  position: relative;
  margin-bottom: 2em;
  width: 100%;
  box-shadow: var(--card-shadow); /* Ombra per il header */
  animation: fadeIn 0.8s ease-out; /* Animazione di ingresso */
}

/* CSS saluti e sottotesto */
.saluti {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5em; /* Spazio tra icona e testo */
}

.testo-saluto {
  font-size: 2em;
  font-weight: 600;
  margin: 0;
}

.icona-saluto {
  font-size: 2.5em;
  animation: saluta 2s infinite;
  /* 
  La proprietà 'transform-origin' specifica il punto di riferimento attorno al quale viene applicata l'animazione.
  In questo caso, '70% 70%' indica che il punto di origine si trova al 70% della larghezza e al 70% dell'altezza dell'elemento.
  Questo sposta il centro dell'animazione verso il basso a destra rispetto al centro standard (50% 50%).
*/
  transform-origin: 70% 70%;
}

.sottotesto {
  font-size: 1.3em;
}

.logout-btn-container {
  position: absolute;
  top: 1em;
  right: 1em;
}

/* Stile del pulsante di logout */
.logout-btn {
  background-color: rgba(255, 255, 255, 0.2);
  color: white;
  border: none;
  padding: 0.5em 1em; /* Padding per il pulsante */
  border-radius: 2em;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5em; /* Spazio tra icona e testo */
  transition: all 0.3s ease;
}

.logout-btn:hover {
  background-color: rgb(201, 36, 36);
  transform: translateY(-2px);
}

.logout-btn:active {
  transform: translateY(0);
  background-color: #ba2815; /* Colore più scuro al click */
}

/* Container delle cards */
.cards-container {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: row;
  gap: 1em;
}

.card {
  background-color: var(--card-bg);
  border-radius: var(--border-radius);
  overflow: hidden;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  animation: fadeIn 0.8s ease-out;
  width: 100%;
}

.card:hover {
  transform: translateY(
    -5px
  ); /* Effetto di sollevamento al passaggio del mouse */
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1),
    0 10px 10px -5px rgba(0, 0, 0, 0.04);
}

.card-header {
  padding: 1em;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5em; /* Spazio tra icona e titolo */
  border-bottom: 1px solid #e5e7eb;
}

.note-card .card-header {
  background: linear-gradient(90deg, #e0e7ff 0%, #c7d2fe 100%);
  color: var(--primary-color);
}

.event-card .card-header {
  background: linear-gradient(90deg, #e0e7ff 0%, #c7d2fe 100%);
  color: var(--secondary-color);
}

.pomodoro-card .card-header {
  background: linear-gradient(90deg, #e0e7ff 0%, #c7d2fe 100%);
  color: var(--accent-color);
}

.card-header i {
  font-size: 1em;
}

.card-header h2 {
  margin: 0;
  font-size: 1.3em;
  font-weight: 600;
}

.card-content {
  max-width: 100%;
  padding: 1em;
  min-height: 150px;
}

/* Stile note */

.note-content {
  display: flex;
  flex-direction: column;
  gap: 1em;
}

.titolo-nota {
  margin: 0;
  font-size: 1.2em;
  color: var(--primary-color);
}

.categoria-nota {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5em;
  font-size: 0.9em;
}

.label-categoria {
  font-weight: 600;
}

.testo-categoria {
  background-color: var(--primary-color);
  color: white;
  padding: 0.25em 0.75em;
  border-radius: 1em;
  font-size: 0.9em;
}

/* 
  Descrizione della nota. 
  Viene usato -webkit-line-clamp e -webkit-box-orient per limitare il numero di righe mostrate e troncare il testo.
  Queste proprietà sono specifiche per browser basati su WebKit (come Chrome e Safari), 
  e permettono di mostrare solo un certo numero di righe di testo, aggiungendo "..." se il contenuto è più lungo.
*/
.descrizione-nota {
  margin: 0;
  line-height: 1.5; /* Spazio tra le righe per una migliore leggibilità */
  overflow: hidden;
  text-overflow: ellipsis; /* Troncamento del testo */
  display: -webkit-box; /* Per il supporto a WebKit */
  -webkit-line-clamp: 5; /* Mostra massimo 3 righe */
  line-clamp: 3; /* Per il supporto a Firefox */
  -webkit-box-orient: vertical; /* Orientamento verticale per WebKit */
  max-width: 100%; /* Limita la larghezza massima per evitare overflow */
}

.info-nota {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-top: 0.5rem;
  font-size: 0.8rem;
  color: var(--gray-color);
}

.data-nota {
  display: flex;
  align-items: center;
  gap: 0.5em;
}

/* Stati vuoti */
.testo-vuoto {
  color: var(--gray-color);
  text-align: center;
  font-style: italic;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
}

.error-state {
  color: #ef4444;
  text-align: center;
}

/* Animations */
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateX(-20px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes saluta {
  0% {
    transform: rotate(0deg);
  }
  10% {
    transform: rotate(14deg);
  }
  20% {
    transform: rotate(-8deg);
  }
  30% {
    transform: rotate(14deg);
  }
  40% {
    transform: rotate(-4deg);
  }
  50% {
    transform: rotate(10deg);
  }
  60% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(0deg);
  }
}

/* Responsive Design */
@media (max-width: 700px) {
  .cards-container {
    flex-direction: column;
    align-items: center;
  }
  .card {
    max-width: 90vw;
    width: 100%;
  }

  .logout-btn-container {
    position: static;
    margin-top: 1em;
  }
}

/* Icone FontAwesome */
.fas {
  display: inline-block;
  width: 1em;
  height: 1em;
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
}
</style>
