<template>
  <section class="calendar-preview">
    <!-- Selettori mese/anno -->
    <div class="calendar-box">
      <div class="calendar-header">
        <h1>Calendario</h1>
          <div class="selectors" aria-label="Selezione mese e anno">
            <button @click="changeMonth(-1)" aria-label="Mese precedente">«</button>
            <label>
              <span class="visually-hidden">Mese</span>
              <select v-model="currentMonth">
                <option v-for="(m, i) in months" :key="i" :value="i">{{ m }}</option>
              </select>
            </label>

            <label>
              <span class="visually-hidden">Anno</span>
              <select v-model="currentYear">
                <option v-for="y in years" :key="y" :value="y">{{ y }}</option>
              </select>
            </label>
            <button @click="changeMonth(1)" aria-label="Mese successivo">»</button>
          </div>
      </div>

      <Calendar
      :currentYear="currentYear"
      :currentMonth="currentMonth"
      :selectedDay="selectedDay"
      :events="events"
      :virtualDate="virtualDate"
      @select-day="selectDay"
    />
    
    </div>

    <EventList
      v-if="selectedDay !== null && !showForm"
      :selectedDateString="selectedDateString"
      :events="eventsForSelectedDay"
      @close="closeEventList"
      @edit-event="editEvent"
      @delete-event="deleteEvent"
    />

    <EventForm
      v-if="showForm"
      :modelValue="formModel"
      :editIndex="editIndex"
      @save="saveEvent"
      @cancel="closeForm"
    />

    <TodayEvents 
    :events="eventsForToday" 
    :todayDateString="todayDateString" 
    />

    <button v-if="selectedDay !== null && !showForm" @click="openNewEventForm">
      Nuovo Evento
    </button>
  </section>
</template>

<script>
let backendHost = `http://${window.location.hostname}:3000`;

import { getVirtualTime } from "@/api";
import { computed, onMounted, reactive, ref } from "vue";
import Calendar from "./CalendarGrid.vue";
import EventForm from "./EventForm.vue";
import EventList from "./EventList.vue";
import TodayEvents from "./TodayEvents.vue";

export default {
  name: "CalendarPreview",
  components: {
    Calendar,
    EventList,
    EventForm,
    TodayEvents,
  },
  setup() {
    const currentDate = ref(new Date());
    const virtualDate = computed(() => {
      return typeof currentDate.value === "string"
        ? new Date(currentDate.value)
        : currentDate.value;
    });
    const currentYear = ref(virtualDate.value.getFullYear());
    const currentMonth = ref(virtualDate.value.getMonth());
    const selectedDay = ref(null);
    const events = reactive({});

    async function fetchEvents() {
      const author = window.localStorage.getItem("username") || "Anonimo";
      try {
        const res = await fetch(
          `${backendHost}/api/calendar/getAll?author=${encodeURIComponent(author)}`
        );
        if (!res.ok) {
          Object.keys(events).forEach((k) => delete events[k]);
          return;
        }
        const data = await res.json();

        const eventsTemp = {};
        // Svuota events
        Object.keys(events).forEach((k) => delete events[k]);
        // Inserisci eventi per ogni giorno
        for (const ev of data.eventi) {
          const d = new Date(ev.data_ev);

          if (ev.repeat && ev.repeat !== "none") {
            const duration = ev.repeatDuration || 12;
            const frequency = ev.repeatFrequency || 1;

            for (let i = 0; i < duration; i++) {
              const repeatDate = new Date(d);

              if (ev.repeat === "monthly") {
                repeatDate.setMonth(d.getMonth() + i * frequency);
              } else if (ev.repeat === "weekly") {
                repeatDate.setDate(d.getDate() + i * frequency * 7);
              } else if (ev.repeat === "daily") {
                repeatDate.setDate(d.getDate() + i * frequency);
              } else {
                continue;
              }

              if (
                repeatDate.getFullYear() === currentYear.value &&
                repeatDate.getMonth() === currentMonth.value
              ) {
                const key = formatDateKey(
                  repeatDate.getFullYear(),
                  repeatDate.getMonth() + 1,
                  repeatDate.getDate()
                );
                if (!eventsTemp[key]) eventsTemp[key] = [];
                eventsTemp[key].push(ev);
              }
            }
          } else {
            const key = formatDateKey(
              d.getFullYear(),
              d.getMonth() + 1,
              d.getDate()
            );
            if (!eventsTemp[key]) eventsTemp[key] = [];
            eventsTemp[key].push(ev);
          }
        }

        // Aggiorna reactive events
        Object.keys(events).forEach((k) => delete events[k]);
        for (const key in eventsTemp) {
          events[key] = eventsTemp[key];
        }

      } catch (err) {
        Object.keys(events).forEach((k) => delete events[k]);
      }
    }

    onMounted(async () => {
      try {
        const virtualStr = await getVirtualTime();
        if (
          virtualStr &&
          typeof virtualStr === "string" &&
          virtualStr.trim() !== ""
        ) {
          const parsed = new Date(virtualStr);
          if (!isNaN(parsed)) {
            currentDate.value = parsed;
            currentYear.value = parsed.getFullYear();
            currentMonth.value = parsed.getMonth();
          } else {
            console.warn("Data virtuale non valida, uso quella reale.");
          }
        }
      } catch (e) {
        console.warn("Errore nel recupero della Time Machine:", e);
      }
      await fetchEvents();
    });

    const months = [
      "Gennaio",
      "Febbraio",
      "Marzo",
      "Aprile",
      "Maggio",
      "Giugno",
      "Luglio",
      "Agosto",
      "Settembre",
      "Ottobre",
      "Novembre",
      "Dicembre",
    ];

    const years = [];
    for (let y = currentYear.value - 5; y <= currentYear.value + 5; y++)
      years.push(y);

    const showForm = ref(false);
    const editIndex = ref(null);

    function formatDateKey(y, m, d) {
      return `${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
    }

    function addEventToDate(key, eventObj) {
      if (!events[key]) events[key] = [];
      events[key].push(eventObj);
    }

    const selectedDateString = computed(() => {
      if (selectedDay.value === null) return "";
      return `${selectedDay.value} ${months[currentMonth.value]} ${
        currentYear.value
      }`;
    });

    const eventsForSelectedDay = computed(() => {
      if (selectedDay.value === null) return [];
      const key = formatDateKey(
        currentYear.value,
        currentMonth.value + 1,
        selectedDay.value
      );
      return events[key] || [];
    });

    const todayDateString = computed(
      () =>
        `${currentDate.value.getDate()} ${
          months[currentDate.value.getMonth()]
        } ${currentDate.value.getFullYear()}`
    );

    const eventsForToday = computed(() => {
      const key = formatDateKey(
        currentDate.value.getFullYear(),
        currentDate.value.getMonth() + 1,
        currentDate.value.getDate()
      );
      return events[key] || [];
    });

    const formModel = computed(() => {
      if (editIndex.value === null || selectedDay.value === null) {
        return null;
      }
      const key = formatDateKey(
        currentYear.value,
        currentMonth.value + 1,
        selectedDay.value
      );
      return events[key]?.[editIndex.value] || null;
    });

    function resetForm() {
      editIndex.value = null;
    }

    function openNewEventForm() {
      resetForm();
      showForm.value = true;
    }

    function closeForm() {
      resetForm();
      showForm.value = false;
    }

    function closeEventList() {
      selectedDay.value = null;
      showForm.value = false;
    }

    function selectDay(day) {
      selectedDay.value = day;
      showForm.value = false;
    }

    function saveEvent(eventObj) {
      const key = formatDateKey(
        currentYear.value,
        currentMonth.value + 1,
        selectedDay.value
      );
      let dateISO = `${currentYear.value}-${String(
        currentMonth.value + 1
      ).padStart(2, "0")}-${String(selectedDay.value).padStart(2, "0")}`;

      if (!eventObj.allDay && eventObj.startTime) {
        dateISO = `${dateISO}T${eventObj.startTime}`;
      }

      const author = window.localStorage.getItem("username") || "Anonimo";

      if (!author) {
        console.error("Username non trovato nel localStorage.");
        return;
      }

      const payload = {
        author,
        title: eventObj.title,
        description: eventObj.description,
        date: dateISO,
        allDay: eventObj.allDay,
        startTime: eventObj.startTime,
        endTime: eventObj.endTime,
        repeat: eventObj.repeat ? true : false,
        repeatFrequency: eventObj.repeat ? eventObj.repeatFrequency : null,
        repeatDuration: eventObj.repeat ? eventObj.repeatDuration : null,
        repeatId: eventObj.repeat ? (eventObj.repeatId || `repeat-${Date.now()}`) : null,
        location: eventObj.location,
        latitude: eventObj.latitude,
        longitude: eventObj.longitude,
      };

      if (editIndex.value !== null) {
        const event = events[key]?.[editIndex.value];
        if (!event) return;
        fetch(`${backendHost}/api/calendar/update/${event.id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            title: eventObj.title,
            description: eventObj.description,
            date: dateISO,
            location: eventObj.location,
            latitude: eventObj.latitude,
            longitude: eventObj.longitude,
          }),
        })
          .then(async (res) => {
            if (res.ok) {
              closeForm();
              fetchEvents();
            } else {
              alert("Errore modifica evento");
            }
          })
          .catch(() => {
            alert("Errore di rete");
          });
      } else {
        fetch(`${backendHost}/api/calendar/save`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(payload),
        })
          .then(async (res) => {
            const data = await res.json();
            if (res.ok) {
              addEventToDate(key, eventObj);
              closeForm();
              fetchEvents();
            } else {
              alert(data.error || "Errore salvataggio evento");
            }
          })
          .catch(() => {
            alert("Errore di rete");
          });
      }
    }

    const editingRepeatId = ref(null);

    function editEvent(index) {
      editIndex.value = index;
      const key = formatDateKey(
        currentYear.value,
        currentMonth.value + 1,
        selectedDay.value
      );
      const ev = events[key]?.[index];
      if (ev?.repeatId) {
        editingRepeatId.value = ev.repeatId;
      }
      showForm.value = true;
    }

    function deleteEvent(index) {
      const key = formatDateKey(
        currentYear.value,
        currentMonth.value + 1,
        selectedDay.value
      );
      const eventToDelete = events[key]?.[index];
      if (!eventToDelete) return;

      const confirmMsg = eventToDelete.repeatId
        ? "Questo evento è ricorrente. Vuoi eliminare solo questo evento o tutta la serie?"
        : "Sei sicuro di voler eliminare questo evento?";

      if (confirm(confirmMsg)) {
        const url = eventToDelete.repeatId
          ? `${backendHost}/api/calendar/deleteRepeat/${eventToDelete.repeatId}`
          : `${backendHost}/api/calendar/delete/${eventToDelete.id}`;

        fetch(url, {
          method: "DELETE",
        })
          .then((res) => {
            if (res.ok) {
              fetchEvents();
              closeEventList();
            } else {
              alert("Errore eliminazione evento");
            }
          })
          .catch(() => {
            alert("Errore di rete");
          });
      }
    }

    function changeMonth(delta) {
      let newMonth = currentMonth.value + delta;
      let newYear = currentYear.value;
      if (newMonth < 0) {
        newMonth = 11;
        newYear--;
      } else if (newMonth > 11) {
        newMonth = 0;
        newYear++;
      }
      currentMonth.value = newMonth;
      currentYear.value = newYear;
      selectedDay.value = null;
      fetchEvents();
    }

    return {
      months,
      years,
      currentYear,
      currentMonth,
      selectedDay,
      events,
      virtualDate,
      showForm,
      editIndex,
      selectedDateString,
      eventsForSelectedDay,
      todayDateString,
      eventsForToday,
      formModel,
      openNewEventForm,
      closeForm,
      closeEventList,
      selectDay,
      saveEvent,
      editEvent,
      deleteEvent,
      changeMonth,
    };
  },
};
</script>

<style scoped>

.calendar-preview {
  font-family: Arial, sans-serif;
  max-width: 900px;
  margin: auto;
  padding: 10px;
  display: grid;
  grid-template-columns: 2fr 1fr;
  gap: 10px;
}

.calendar-box {
  background-image: -webkit-linear-gradient(rgb(246, 248, 195), rgb(196, 249, 196), rgb(170, 221, 245));
  border: 1px solid #ddd;
  border-radius: 8px;
  padding: 10px;
}

.selectors {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 10px;
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  border: 0;
  white-space: nowrap;
  clip-path: inset(100%);
  clip: rect(0 0 0 0);
  overflow: hidden;
}

button {
  background-color: #007bff;
  border: none;
  padding: 6px 12px;
  color: white;
  border-radius: 4px;
  cursor: pointer;
}

button:hover {
  background-color: #0056b3;
}

button:disabled {
  background-color: #cccccc;
  cursor: not-allowed;
}
</style>