<template>
  <section class="event-list" aria-label="Eventi del giorno selezionato">
    <header>
      <h3>Eventi del {{ selectedDateString }}</h3>
      <button @click="$emit('close')">Chiudi</button>
    </header>
    <p v-if="events.length === 0">Nessun evento</p>
    <ul v-else>
      <li v-for="(event, index) in events" :key="index" class="event-item">
        <strong>{{ event.titolo }}</strong>: {{event.descr}}<br>{{ event.allDay ? 'Tutto il giorno' : event.startTime + ' - ' + event.endTime }}
        <button @click="$emit('edit-event', index)" title="Modifica">✏️</button>
        <button @click="$emit('delete-event', index)" title="Elimina">🗑️</button>
      </li>
    </ul>
  </section>
</template>

<script>
export default {
  props: {
    selectedDateString: String,
    events: Array
  }
};
</script>

<style scoped>
.event-list {
  background: #f9f9f9;
  border: 1px solid #ddd;
  padding: 10px;
  border-radius: 6px;
}

.event-item {
  margin-bottom: 6px;
  text-align: left;
}

.event-item button {
  margin-left: 5px;
  cursor: pointer;
}
</style>