<template>
  <div class="container-note">
    <h1 class="logo">📓 Note 📓</h1>
    <div id="contenitore_appunti">
      <label for="title-note">Crea o modifica un appunto:</label>
      <input
        v-model="newNote.titolo"
        type="text"
        placeholder="Titolo"
        class="note"
        id="title-note"
      />
      <input
        v-model="newNote.cat"
        type="text"
        placeholder="CATEGORIA"
        class="note"
      />
      <textarea
        v-model="newNote.descr"
        type="text"
        placeholder="Appunti..."
        class="note"
        id="descrizione-note"
      />
      <div class="date-container">
        <input
          v-model="newNote.data_md"
          type="date"
          class="note"
          id="date-note"
        />
      </div>
      <button @click="addNote" class="button-note">Aggiungi nota</button>
    </div>
    <br />

    <div>
      <b>Ordina per: </b>
      <select v-model="ordine" class="note">
        <option value="data_md">Data di modifica</option>
        <option value="titolo">Titolo</option>
        <option value="descr">Lunghezza contenuto</option>
      </select>
    </div>
    <br />
  </div>

  <section id="flexNote">
    <article v-for="nota in ordinaNote" :key="nota.id">
      <h3>{{ nota.titolo }}</h3>
      <p>
        <b>Categoria:</b> <i>{{ nota.cat }}</i>
      </p>
      <p v-html="renderMarkdown(nota.descr)"></p>
      <!---<p>{{ nota.descr }}</p>--->
      <small>Data di creazione: {{ formatDate(nota.data_cr) }}</small
      ><br />
      <small>Ultima modifica: {{ formatDate(nota.data_md) }}</small
      ><br />
      <button
        @click="copNote(nota.id)"
        title="Copia il testo della nota nel form, creandone una nuova"
        class="button-note"
      >
        Copia nota
      </button>
      <button
        @click="modNote(nota.id)"
        title="Permette di modificare la nota, inserendo i dati nel form"
        class="button-note"
      >
        Modifica nota
      </button>
      <button
        @click="cancNote(nota.id)"
        title="Cancella completamente la nota"
        class="button-note"
      >
        Cancella nota
      </button>
    </article>

    <p v-if="notes.length === 0">Nessuna nota trovata</p>
  </section>
</template>

<style>
.container-note {
  padding: 0.5em;
  min-width: 50%;
  border-radius: 2em;
  font-family: "Poppins", sans-serif;
  background: linear-gradient(135deg, #608dcb 0%, #00d2ff 100%);
}

/* Stili generali del corpo */
body {
  font-family: "Poppins", sans-serif;
  background-color: #f0f2f5;
  color: #333;
}

/* Stile per il contenitore dell'applicazione delle note */
#contenitore_appunti {
  margin: 2em auto;
  padding: 2em;
  background: linear-gradient(
    135deg,
    rgba(255, 255, 255, 0.9),
    rgba(240, 240, 240, 0.9)
  );
  display: flex;
  flex-direction: column;
  gap: 0.5em;
  border-radius: 1em;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);
  width: clamp(300px, 80%, 500px); /* Larghezza responsive */
}

/* Stili per gli input e textarea */
.note {
  border: 1px solid #e0e0e0;
  padding: 0.8em 1em;
  margin-bottom: 1em;
  border-radius: 0.5em;
  font-family: "Poppins", sans-serif;
  font-size: 1em;
  box-sizing: border-box; /* Include padding and border in the element's total width and height */
  transition: all 0.3s ease;
  background-color: rgba(255, 255, 255, 0.8);
}

.note:focus {
  outline: none;
  border-color: #1a56a9;
  box-shadow: 0 0 0 3px rgba(26, 86, 169, 0.2);
}

/* Stile per il titolo della nota */
#title-note {
  text-align: center;
  font-weight: 700;
  text-transform: uppercase;
}

/* Stile per la descrizione della nota */
#descrizione-note {
  min-height: 10em;
  resize: vertical; /* Permette il ridimensionamento verticale */
}

/* Contenitore per la data */
.date-container {
  display: flex;
  width: 100%;
}

/* Stile per i pulsanti */
.button-note {
  padding: 0.8em 1.5em;
  font-size: 1em;
  font-weight: 600;
  font-family: "Poppins", sans-serif;
  color: white;
  background: linear-gradient(135deg, #1a56a9 0%, #039bbd 100%);
  border: none;
  border-radius: 5em;
  cursor: pointer;
  transition: all 0.3s ease;
  margin: 0.5em 0.2em;
}

.button-note:hover {
  transform: translateY(-3px);
  background: linear-gradient(135deg, #2367c0 0%, #04b2d9 100%);
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
}

.button-note:active {
  transform: translateY(0);
}

/* Sezione per la visualizzazione delle note */
#flexNote {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: 1.5em;
  padding: 1em;
  width: 100%;
}

/* Stile per ogni singola nota */
#flexNote article {
  background: white;
  border-radius: 1em;
  padding: 1.5em;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  transition: box-shadow 0.3s ease, transform 0.3s ease;
  display: flex;
  flex-direction: column;
}

#flexNote article:hover {
  transform: translateY(-5px);
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.1);
}

#flexNote h3 {
  font-family: "Poppins", sans-serif;
  font-size: 1.4em;
  font-weight: 600;
  color: #1a56a9;
  margin-top: 0;
  margin-bottom: 0.5em;
}

#flexNote p {
  flex-grow: 1; /* Fa in modo che il paragrafo occupi lo spazio disponibile */
  line-height: 1.6;
}

#flexNote small {
  margin-top: 1em;
  color: #666;
}

/* Stile per il dropdown di ordinamento */
div > b {
  font-weight: 600;
}
</style>

<script>
let backendHost = `http://${window.location.hostname}:3000`;
import { marked } from "marked";

export default {
  data() {
    return {
      ordine: "data_md",
      notes: [],
      newNote: {
        autore: "",
        id: -1,
        titolo: "",
        cat: "",
        descr: "",
        data_cr: "",
        data_md: "",
      },
      virtualDate: "",
    };
  },
  methods: {
    async fetchVirtualDate() {
      // Ottieni la data virtuale dal backend (time machine)
      try {
        const res = await fetch(`${backendHost}/api/time-machine`);
        if (!res.ok) throw new Error("Errore nel recupero della data virtuale");
        const data = await res.json();
        // data.time è in formato ISO, estrai solo la parte data (YYYY-MM-DD)
        this.virtualDate = data.time.slice(0, 10);
      } catch (e) {
        // fallback: data di sistema
        this.virtualDate = new Date().toISOString().slice(0, 10);
      }
    },
    async fetchNotes() {
      try {
        const user = localStorage.getItem("username");
        if (!user) {
          console.error("Username non trovato nel localStorage.");
          return;
        }

        const risposta = await fetch(
          `${backendHost}/api/note/getAll?autore=${encodeURIComponent(user)}`
        );
        if (!risposta.ok) {
          this.notes = [];
          return;
        }

        const data = await risposta.json();
        this.notes = data.TutteNote;
      } catch (error) {
        console.error("Errore nel recupero delle note:", error);
      }
    },

    async addNote() {
      const autore = localStorage.getItem("username");
      if (!autore) {
        console.error("Username non trovato nel localStorage.");
        return;
      }

      const { titolo, cat, descr, data_md, id } = this.newNote;

      if (!titolo || !cat || !descr || !data_md) {
        alert("Attenzione! Non hai compilato tutti i campi!");
        return;
      }

      try {
        let data_cr;
        let noteId = id;
        if (noteId === -1) {
          // Nuova nota: data di creazione = data virtuale
          data_cr = this.virtualDate;
          const ultimoID = await fetch(
            `${backendHost}/api/note/getID?autore=${encodeURIComponent(autore)}`
          );
          const dati = await ultimoID.json();
          noteId = dati.ID;
        } else {
          // Nota esistente: mantieni la data di creazione
          data_cr = this.newNote.data_cr;
        }

        // Usa la data virtuale anche per la modifica
        const dataMdToSend = this.virtualDate;

        await fetch(`${backendHost}/api/note/save`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            autore,
            id: noteId,
            titolo,
            cat,
            descr,
            data_cr,
            data_md: dataMdToSend,
          }),
        });

        // Reset campi
        this.newNote = {
          autore: "",
          id: -1,
          titolo: "",
          cat: "",
          descr: "",
          data_cr: "",
          data_md: this.virtualDate,
        };

        this.fetchNotes();
      } catch (err) {
        console.error("Errore nel salvataggio della nota:", err);
      }
    },

    async cancNote(id) {
      try {
        const autore = localStorage.getItem("username");
        if (id == null) {
          console.error("ID non valido.");
          return;
        }

        await fetch(`${backendHost}/api/note/delete`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ autore, id }),
        });

        this.fetchNotes();
      } catch (err) {
        console.error("Errore nell'eliminazione della nota:", err);
      }
    },

    copNote(id) {
      const notaCop = this.notes.find((n) => n.id === id);
      if (!notaCop) {
        alert("Nota non trovata.");
        return;
      }
      // Quando copi, imposta la data di modifica e creazione alla data virtuale
      this.newNote = {
        id: -1,
        titolo: notaCop.titolo,
        cat: notaCop.cat,
        descr: notaCop.descr,
        data_cr: this.virtualDate,
        data_md: this.virtualDate,
      };
    },

    modNote(id) {
      const notaMod = this.notes.find((n) => n.id === id);
      if (!notaMod) {
        alert("Nota non trovata.");
        return;
      }
      // Quando modifichi, aggiorna la data di modifica alla data virtuale
      this.newNote = {
        autore: localStorage.getItem("username"),
        id: notaMod.id,
        titolo: notaMod.titolo,
        cat: notaMod.cat,
        descr: notaMod.descr,
        data_cr: notaMod.data_cr,
        data_md: this.virtualDate,
      };
    },

    renderMarkdown(t) {
      return marked.parse(t);
    },

    formatDate(data) {
      return new Date(data).toLocaleDateString();
    },
  },

  computed: {
    ordinaNote() {
      let ordinate = [...this.notes];

      switch (this.ordine) {
        case "titolo":
          ordinate.sort((a, b) => a.titolo.localeCompare(b.titolo));
          break;
        case "descr":
          ordinate.sort((a, b) => a.descr.length - b.descr.length).reverse();
          break;
        default:
          ordinate.sort((a, b) => new Date(b.data_md) - new Date(a.data_md));
          break;
      }

      return ordinate;
    },
  },

  async mounted() {
    await this.fetchVirtualDate();
    // Imposta la data virtuale come default per il form
    this.newNote.data_md = this.virtualDate;
    this.fetchNotes();
  },
};
</script>
