<template>
    <aside class="today-events">
        <h3>Eventi di oggi ({{ todayDateString }})</h3>
        <p v-if="events.length === 0">Nessun evento</p>
        <ul v-else>
            <li v-for="(event, idx) in events" :key="idx" class="event-item">
                <strong>{{ event.titolo }}</strong>: ({{ event.allDay ? 'Tutto il giorno' : event.startTime + ' - ' + event.endTime }})
            </li>
          </ul>
    </aside>
</template>
  
<script>
  export default {
  props: {
    events: Array,
    todayDateString: String,
  }
};
</script>
  
<style scoped>
  .today-events {
    border: 1px solid #ddd;
    background: #f3f3f3;
    padding: 10px;
    border-radius: 6px;
    height: fit-content;
  }
  
  .event-item {
    margin-bottom: 6px;
    text-align: left;
  }
</style>