<template>
  <form class="event-form" @submit.prevent="onSubmit">
    <h3>{{ editIndex === null ? "Nuovo evento" : "Modifica evento" }}</h3>

    <label>
      Titolo:
      <input v-model="form.title" required />
    </label>

    <label>
      Descrizione:
      <textarea v-model="form.description"></textarea>
    </label>

    <label>
      <input type="checkbox" v-model="form.allDay" /> Tutto il giorno
    </label>

    <div v-if="!form.allDay" class="time-selectors">
      <label>
        Inizio:
        <select v-model.number="form.startHour">
          <option v-for="h in 24" :key="h" :value="h - 1">
            {{ (h - 1).toString().padStart(2, "0") }}
          </option>
        </select>
        :
        <select v-model.number="form.startMinute">
          <option v-for="m in 12" :key="m" :value="(m - 1) * 5">
            {{ ((m - 1) * 5).toString().padStart(2, "0") }}
          </option>
        </select>
      </label>
      <label>
        Fine:
        <select v-model.number="form.endHour">
          <option v-for="h in 24" :key="h" :value="h - 1">
            {{ (h - 1).toString().padStart(2, "0") }}
          </option>
        </select>
        :
        <select v-model.number="form.endMinute">
          <option v-for="m in 12" :key="m" :value="(m - 1) * 5">
            {{ ((m - 1) * 5).toString().padStart(2, "0") }}
          </option>
        </select>
      </label>
    </div>

    <label>
      Posizione evento:
      <input v-model="form.location" placeholder="Indirizzo o luogo" />
    </label>
    <div id="map" class="event-map"></div>
    <div v-if="form.latitude && form.longitude" class="coords">
      Coordinate selezionate: {{ form.latitude.toFixed(5) }},
      {{ form.longitude.toFixed(5) }}
    </div>

    <label>
      <input type="checkbox" v-model="form.repeat" /> Evento ripetuto
    </label>

    <div v-if="form.repeat" class="repeat-options">
      <label>
        Frequenza:
        <select v-model="form.repeatFrequency">
          <option value="weekly">Settimanale</option>
          <option value="monthly">Mensile</option>
          <option value="yearly">Annuale</option>
        </select>
      </label>
      <label>
        Durata:
        <select v-model="form.repeatDuration">
          <option value="1">1 mese</option>
          <option value="6">6 mesi</option>
          <option value="12">1 anno</option>
          <option value="24">2 anni</option>
          <option value="forever">Per sempre</option>
        </select>
      </label>
    </div>

    <button type="submit">Salva</button>
    <button type="button" @click="$emit('cancel')">Annulla</button>
  </form>

  <div v-if="form.repeatId" class="repeat-edit-mode">
    <label><strong>Modifica evento ricorrente:</strong></label>
    <div>
      <label>
        <input type="radio" value="this" v-model="repeatEditMode" />
        Solo questo evento
      </label>
    </div>
    <div>
      <label>
        <input type="radio" value="all" v-model="repeatEditMode" />
        Tutti gli eventi (anche passati)
      </label>
    </div>
    <div>
      <label>
        <input type="radio" value="future" v-model="repeatEditMode" />
        Da oggi in poi
      </label>
    </div>
  </div>
</template>

<script>
export default {
  emits: ['save', 'cancel'],
  
  props: {
    modelValue: Object,
    editIndex: Number,
  },

  data() {
    return {
      form: {
        title: "",
        description: "",
        allDay: false,
        startHour: 9,
        startMinute: 0,
        endHour: 10,
        endMinute: 0,
        repeat: false,
        repeatFrequency: "weekly",
        repeatDuration: "1",
        repeatId: null,
        location: "",
        latitude: null,
        longitude: null,
      },
      repeatEditMode: "this",
    };
  },

  mounted() {
    // Lazy load Leaflet CSS/JS if not present
    if (!window.L) {
      const leafletCss = document.createElement("link");
      leafletCss.rel = "stylesheet";
      leafletCss.href = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.css";
      document.head.appendChild(leafletCss);
      const leafletJs = document.createElement("script");
      leafletJs.src = "https://unpkg.com/leaflet@1.9.4/dist/leaflet.js";
      leafletJs.onload = this.initMap;
      document.body.appendChild(leafletJs);
    } else {
      this.initMap();
    }
  },

  watch: {
    modelValue: {
      immediate: true,
      handler(newVal) {
        this.repeatEditMode = "this";
        if (newVal) {
          Object.assign(this.form, newVal);
          this.form.repeatId = newVal.repeatId || null;
        } else {
          this.form = {
            title: "",
            description: "",
            allDay: false,
            startHour: 9,
            startMinute: 0,
            endHour: 10,
            endMinute: 0,
            repeat: false,
            repeatFrequency: "weekly",
            repeatDuration: "1",
            repeatId: null,
            location: "",
            latitude: null,
            longitude: null,
          };
        }
      },
    },
  },

  methods: {
    initMap() {
      if (this._mapInitialized) return;
      this._mapInitialized = true;
      // Default center: Italia
      const defaultLat = this.form.latitude || 41.8719;
      const defaultLng = this.form.longitude || 12.5674;
      this._map = window.L.map("map").setView([defaultLat, defaultLng], 6);
      window.L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
        attribution: "© OpenStreetMap contributors",
      }).addTo(this._map);
      this._marker = window.L.marker([defaultLat, defaultLng], {
        draggable: true,
      }).addTo(this._map);
      this._marker.on("dragend", (e) => {
        const pos = e.target.getLatLng();
        this.form.latitude = pos.lat;
        this.form.longitude = pos.lng;
      });
      this._map.on("click", (e) => {
        this._marker.setLatLng(e.latlng);
        this.form.latitude = e.latlng.lat;
        this.form.longitude = e.latlng.lng;
      });
      // Aggiorna marker se già presenti lat/lon
      if (this.form.latitude && this.form.longitude) {
        this._marker.setLatLng([this.form.latitude, this.form.longitude]);
        this._map.setView([this.form.latitude, this.form.longitude], 12);
      }
    },
    pad(n) {
      return n.toString().padStart(2, "0");
    },

    validateAndFormatTime(sh, sm, eh, em) {
      if (sh === null || sm === null || eh === null || em === null)
        return { error: "Compila tutti i campi orari." };

      const startTotal = sh * 60 + sm;
      const endTotal = eh * 60 + em;

      if (endTotal <= startTotal) {
        return {
          error: "L'orario di fine deve essere successivo a quello di inizio.",
        };
      }

      return {
        startTime: `${this.pad(sh)}:${this.pad(sm)}`,
        endTime: `${this.pad(eh)}:${this.pad(em)}`,
        error: null,
      };
    },

    onSubmit() {
      if (!this.form.title.trim()) {
        alert("Inserisci un titolo per l'evento.");
        return;
      }

      let startTime = "00:00";
      let endTime = "23:59";
      if (!this.form.allDay) {
        const {
          startTime: s,
          endTime: e,
          error,
        } = this.validateAndFormatTime(
          this.form.startHour,
          this.form.startMinute,
          this.form.endHour,
          this.form.endMinute
        );
        if (error) {
          alert(error);
          return;
        }
        startTime = s;
        endTime = e;
      }

      const eventObj = {
        title: this.form.title.trim(),
        description: this.form.description.trim(),
        allDay: this.form.allDay,
        startTime,
        endTime,
        repeat: this.form.repeat,
        repeatFrequency: this.form.repeat ? this.form.repeatFrequency : null,
        repeatDuration: this.form.repeat ? parseInt(this.form.repeatDuration) : null,
        location: this.form.location,
        latitude: this.form.latitude,
        longitude: this.form.longitude,
      };

      this.$emit(
        "save",
        { ...eventObj, repeatId: this.form.repeatId },
        this.repeatEditMode
      );
    },
  },
};
</script>

<style scoped>
.event-form {
  background: #f9f9f9;
  border: 1px solid #ddd;
  padding: 10px;
  border-radius: 6px;
  grid-column: 1 / span 2;
}

.time-selectors label {
  margin-right: 10px;
}

.repeat-options label {
  display: block;
  margin-top: 5px;
}

button {
  background-color: #007bff;
  border: none;
  padding: 6px 12px;
  color: white;
  border-radius: 4px;
  cursor: pointer;
  margin-top: 8px;
  margin-right: 5px;
}

button:hover {
  background-color: #0056b3;
}

.repeat-edit-mode {
  margin-top: 12px;
  padding: 10px;
  border: 1px solid #ccc;
  background-color: #fffbea;
  border-radius: 6px;
}

.repeat-edit-mode label {
  display: block;
  margin-bottom: 6px;
  cursor: pointer;
}

.repeat-edit-mode input[type="radio"] {
  margin-right: 8px;
}
/* Leaflet map height */
.event-map {
  width: 100%;
  height: 250px;
  margin: 10px 0 10px 0;
  border-radius: 6px;
  border: 1px solid #ccc;
  z-index: 1;
}
.coords {
  font-size: 0.95em;
  color: #333;
  margin-bottom: 10px;
}
</style>