<template>
  <div id="app" :class="appLayoutClass">
    <nav v-if="showNav">
      <article id="time-machine">
        <router-link class="link-time-machine" to="/timeMachine" title="Modifica il tempo"><a>Time Machine</a></router-link>
      </article>
      
      <router-link class="link" to="/home" title="Pagina principale">
        <h1><i class="logo">Selfie🤳</i></h1>
      </router-link>
      
      <!-- Dropdown per dispositivi mobili -->
      <div id="dropdown">
        <button id="dropdown-button"> ☰ Menù </button>
        <div id="dropdown-content">
          <router-link class="link" to="/notes" title="Vai alla pagina Note">Note</router-link>
          <router-link class="link" to="/calendar" title="Vai alla pagina Calendario">Calendario</router-link>
          <router-link class="link" to="/pomodoro" title="Vai alla pagina Pomodoro">Pomodoro</router-link>
          <router-link class="link" to="/profile" title="Vai alla pagina Profilo">Profilo Utente</router-link>
        </div>
      </div>

      <!-- Menu normale per desktop -->
      <section id="desktop-menu">
        <article id="notes">
          <router-link class="link" to="/notes" title="Vai alla pagina Note">Note</router-link>
        </article>
        <article id="calendar">
          <router-link class="link" to="/calendar" title="Vai alla pagina Calendario">Calendario</router-link>
        </article>
        <article id="pomodoro">
          <router-link class="link" to="/pomodoro" title="Vai alla pagina Pomodoro">Pomodoro</router-link>
        </article>
        <article id="profile">
          <router-link class="link" to="/profile" title="Vai alla pagina Profilo">Profilo Utente</router-link>
        </article>
      </section>
    </nav>
    <router-view />
    <footer v-if="showNav">
      <p>Questo è un progetto universitario per il corso di Tecnologie Web dell'Alma Mater Studiorum.</p>
      <i><router-link to="/doc" title="Documentazione del progetto">Documentazione</router-link></i><br><br>
      <p>Copyright © 2025 Matteo Toccarelli, Riccardo Cianci, Alice Zamagni. Tutti i diritti sono riservati.<br>Il progetto contiene anche codice del professore del corso sotto il diritto d'autore © 2024-2025 Fabio Vitali.</p>
    </footer>
  </div>
</template>

<script>
import { computed } from "vue";
import { useRoute } from "vue-router";
import { isAuthenticated } from "./utils/auth";

export default {
  name: "App",

  computed: {
    appLayoutClass() {
      if (this.$route.meta.layout === 'auth') {
        return 'auth-layout';
      }
      return 'default-layout';
    }
  },

  setup() {
    const route = useRoute();

    // Percorsi dove nav e footer non devono essere mostrati
    const noNavPathPrefixes = ["/login", "/signup", "/forgotpassword", "/resetpassword"];

  // Computed property per verificare l'autenticazione
  const isAuthenticated1 = computed(() => {
    return isAuthenticated();
  });
  
  const showNav = computed(() => {
    // Controlla se il percorso corrente corrisponde a uno dei prefissi "no nav"
    const isNoNavPath = noNavPathPrefixes.some(prefix => 
      route.path === prefix || route.path.startsWith(prefix + "/")
    );
    
    // Nascondi la nav se è un percorso "no nav" OPPURE se l'utente non è autenticato e si trova alla root
    return !isNoNavPath && !(route.path === "/" && !isAuthenticated1.value);
  });

    return { showNav, isAuthenticated1 };
  },
};
</script>

<style>
#app {
  background-image: url(https://img.freepik.com/premium-photo/white-calendar-blue-background_539854-1893.jpg);
  background-size: cover;
  background-position: center;
  font-family: 'Poppins', Helvetica, Arial, sans-serif;
  width: 100%;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
}

nav {
  position: sticky;
  top: 0;
  margin: 0;
  width: 100%;
  padding: 0;
  background-image: linear-gradient(0deg, rgba(0, 0, 0, 0), rgba(0, 0, 0, 1));
  display: flex;
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
  z-index: 2;
}

#time-machine {
  padding: 1em;
  margin: 0;
  background-color: black;
  color: white;
  text-align: center;
  font-size: 15px;
  font-weight: 700;
  animation: backgroundColorChange 3s infinite alternate;
  display: flex;
  justify-content: center;
  align-items: center;
  height: 6em;
}

.logo {
  text-align: center;
  color: white;
  font-weight: 700;
  text-shadow: 2px 2px #ff0000;
}

.link {
  color: white;
  text-decoration: none;
  text-shadow: 0.9px 0.9px 0 #000, -0.9px -0.9px 0 #000, 0.9px -0.9px 0 #000,
    -0.9px 0.9px 0 #000;
}

.link-time-machine {
  color: blue;
  text-decoration: none;
}

#desktop-menu article {
  padding: 0.5em 1em;
  height: 100%;
  display: flex;
  justify-content: center;
  align-items: center;
  font-size: 20px;
  font-weight: 700;
  border: 2px solid white;
  backdrop-filter: blur(15px);
}

@keyframes backgroundColorChange {
  0% {
    background-color: black;
    border: 1px solid white;
  }
  50% {
    background-color: white;
    border: 1px solid black;
  }
  100% {
    background-color: black;
    border: 1px solid white;
  }
}

#notes {
  background-color: lightgreen;
}

#calendar {
  background-color: lightpink;
}

#pomodoro {
  background-color: orangered;
}

#profile {
  background-color: lightblue;
}

.background {
  width: 100%;
}

footer {
  background-color: black;
  position: relative;
  bottom: 0px;
  color: white;
  font-size: 0.7em;
  text-align: center;
  width: 100%;
  padding: 0;
}

/* Dropdown */
#dropdown-button {
  background: blue;
  border: 2px solid white;
  color: white;
  padding: 1em;
  cursor: pointer;
  font-size: 15px;
  font-weight: 700;
  text-shadow: 0.9px 0.9px 0 #000, -0.9px -0.9px 0 #000, 0.9px -0.9px 0 #000,
    -0.9px 0.9px 0 #000;
}

#dropdown-button:hover{
  border: 2px solid black;
  transition: border 0.5s ease-in-out;
}

#dropdown-content {
  display: none;
  position: absolute;
  background: darkgoldenrod;
  padding: 0.3em;
  border: 2px solid white;
  z-index: 3;
  font-size: 15px;
  font-weight: 700;
}

#dropdown:hover #dropdown-content{
    display: flex;
    flex-direction: column;
    gap: 2px;
}

/* Telefoni */
@media (max-width: 856px) {
  #desktop-menu {
    display: none;
  }

  #dropdown {
    display: block;
  }
  
  #time-machine{
    height: 100%;
  }
}

/* Desktop */
@media (min-width: 857px) {
  #desktop-menu {
    display: flex;
    flex-direction: row;
    height: 6em;
  }

  #dropdown {
    display: none;
  }
  
  #time-machine{
    height: 6em;
  }
}
</style>